// Process scan result data
const data = $input.first().json.body;

// Validate required fields
if (!data.contract_address || !data.token_name) {
  return {
    status: 'error',
    message: 'Missing required fields'
  };
}

// Calculate risk score and emoji
const score = data.risk_score || 5;
let emoji = '✅';
let status = 'SAFE';

if (score >= 8) {
  emoji = '🚨';
  status = 'HIGH RISK';
} else if (score >= 5) {
  emoji = '⚠️';
  status = 'MODERATE RISK';
} else if (score >= 3) {
  emoji = '⚡';
  status = 'LOW RISK';
}

// Format contract address (shorten)
const contract = data.contract_address;
const shortContract = `${contract.slice(0, 6)}...${contract.slice(-4)}`

// Build issues list
let issuesText = '';
if (data.issues && data.issues.length > 0) {
  issuesText = data.issues.slice(0, 3).map(i => `❌ ${i}`).join('\n');
  if (data.issues.length > 3) {
  issuesText += `\n...and ${data.issues.length - 3} more`;
  }
}

// Format message
const message = `🔍 <b>Community Scan Result</b>

<b>${data.token_name}</b> <code>${shortContract}</code>

${emoji} Risk Score: <b>${score}/10</b> (${status})

${issuesText ? issuesText + '\n\n' : ''}Scanned by: @${data.username || 'anonymous'}
${data.scan_url ? `<a href="${data.scan_url}">View Full Report</a>` : ''}`;

return {
  status: 'success',
  message: message,
  risk_score: score,
  contract: contract
};
